arguments.file_text:
namespace sv_9cfd8bc35d5748f8867a0024252f0c02.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_9cfd8bc35d5748f8867a0024252f0c02.Services

<div class="thread-panel">
    <div class="thread-header">
        <h6>Thread</h6>
        <button class="btn-close" @onclick="OnClose"></button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>
    }

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <div class="thread-reply">
                <div class="reply-header">
                    <span class="reply-author">@reply.Author</span>
                    <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                </div>
                <div class="reply-content">@reply.Content</div>
            </div>
        }
    </div>

    <MessageInput Placeholder="Reply in thread..."
                  ButtonLabel="Reply"
                  OnSend="OnSendReply" />
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.thread-panel {
    height: 100%;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #ddd;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #ddd;
}

.thread-header h6 {
    margin: 0;
    font-weight: 700;
}

.thread-root-message {
    padding: 12px 16px;
    background: #f7f7f7;
    border-bottom: 1px solid #eee;
}

.root-author {
    font-weight: 700;
    font-size: 0.85rem;
    margin-bottom: 2px;
}

.root-content {
    font-size: 0.85rem;
    color: #444;
    line-height: 1.4;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.thread-reply {
    padding: 8px 16px;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 700;
    font-size: 0.85rem;
}

.reply-time {
    font-size: 0.7rem;
    color: #999;
}

.reply-content {
    font-size: 0.85rem;
    color: #333;
    line-height: 1.4;
}

