@page "/chat"
@using sv_9cfd8bc35d5748f8867a0024252f0c02.Services
@inject IChatService ChatService
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(isThreadOpen ? "with-thread" : "")">
        @if (activeChannel is not null)
        {
            <div class="main-header">
                <h5># @activeChannel.Name</h5>
                <span class="main-header-desc">@activeChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages...</div>
                }
                @foreach (var message in messages)
                {
                    <MessageItem Message="message"
                                 ReplyCount="GetReplyCount(message.Id)"
                                 OnOpenThread="() => OpenThread(message)"
                                 OnReact="(emoji) => AddReaction(message.Id, emoji)" />
                }
            </div>

            <MessageInput Placeholder="@($"Message #{activeChannel.Name}")"
                          OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<Message> threadReplies = [];
    private Dictionary<int, int> replyCounts = new();

    private Channel? activeChannel;
    private int activeChannelId;
    private Message? threadRootMessage;
    private bool isThreadOpen;
    private bool isLoadingMore;
    private int messageSkip;
    private const int PageSize = 30;
    private ElementReference messageListRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messageSkip = 0;
        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messageSkip = messages.Count;
        await BuildReplyCounts();
        await ChatService.MarkChannelReadAsync(channelId);
        CloseThread();
    }

    private async Task BuildReplyCounts()
    {
        replyCounts.Clear();
        // Messages with ReplyToId indicate they are replies; count them per root
        foreach (var msg in messages.Where(m => m.ReplyToId.HasValue))
        {
            var rootId = msg.ReplyToId!.Value;
            replyCounts[rootId] = replyCounts.GetValueOrDefault(rootId) + 1;
        }
    }

    private int GetReplyCount(int messageId)
    {
        return replyCounts.GetValueOrDefault(messageId);
    }

    private async Task HandleScroll()
    {
        // Scroll-to-top triggers loading older messages
        // This is a simplified approach; in production you'd use JS interop to detect scroll position
        // For now, we expose the load-more mechanism
    }

    public async Task LoadOlderMessages()
    {
        if (isLoadingMore || activeChannel is null) return;
        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messageSkip, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            messageSkip += older.Count;
            await BuildReplyCounts();
        }
        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;
        var newMessage = await ChatService.SendMessageAsync(activeChannelId, content, null);
        messages.Add(newMessage);
    }

    private async Task OpenThread(Message message)
    {
        // If the message is a reply, open the thread for its root; otherwise it's the root
        var rootId = message.ReplyToId ?? message.Id;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootId) ?? message;
        threadReplies = await ChatService.GetThreadAsync(rootId);
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (threadRootMessage is null || activeChannel is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannelId, content, threadRootMessage.Id);
        threadReplies.Add(reply);
        replyCounts[threadRootMessage.Id] = replyCounts.GetValueOrDefault(threadRootMessage.Id) + 1;
    }

    private async Task AddReaction(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        // Optimistically update local state
        var msg = messages.FirstOrDefault(m => m.Id == messageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, ["You"]));
            }
        }
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-width: 0;
}

.chat-main.with-thread {
    /* When thread is open, main area shrinks */
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    flex-shrink: 0;
}

.main-header {
    padding: 12px 16px;
    border-bottom: 1px solid #ddd;
    background: #fff;
}

.main-header h5 {
    margin: 0;
    font-weight: 700;
}

.main-header-desc {
    font-size: 0.8rem;
    color: #666;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    font-size: 0.8rem;
    color: #999;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 1.1rem;
}

